      "type": "list",
      "variant": "ordered",
      "items": [
        {
          "text": "Definition of Confidential Information. \"Confidential Information\" means any non-public information disclosed by the Disclosing Party to the Receiving Party,\n                whether orally,\n                in writing,\n                or by inspection,\n                including but not limited to trade secrets,\n                business plans,\n                financial data,\n                software,\n                and technical specifications."
        },
        {
          "text": "Obligations of Receiving Party. The Receiving Party agrees to hold all Confidential Information in strict confidence,\n                use it solely for the purpose of evaluating a potential business relationship,\n                and not disclose it to any third party without prior written consent."
        },
        {
          "text": "Exclusions. This Agreement does not apply to information that: (a) is or becomes publicly available through no fault of the Receiving Party; (b) was known to the Receiving Party prior to disclosure; (c) is independently developed without use of Confidential Information; or (d) is required to be disclosed by law or court order."
        },
        {
          "text": "Term and Termination. This Agreement shall remain in effect for a period of two (2) years from the Effective Date. The obligations of confidentiality shall survive termination for an additional three (3) years."
        },
        {
          "text": "Return of Materials. Upon termination or request,\n                the Receiving Party shall promptly return or destroy all Confidential Information and any copies thereof,\n                and certify such destruction in writing."
        },
        {
          "text": "Governing Law. This Agreement shall be governed by and construed in accordance with the laws of the State of Delaware,\n                without regard to conflict of laws principles."
        }
      ]
    },
